class FenwickTree:
    def __init__(self, n):
        self.n = n
        self.tree = [0] * (n + 1)

    def update(self, i, val):
        i += 1
        while i <= self.n:
            self.tree[i] += val
            i += i & (-i)

    def query(self, i):
        i += 1
        res = 0
        while i > 0:
            res += self.tree[i]
            i -= i & (-i)
        return res

def count_smaller_after_self(nums):
    n = len(nums)
    sorted_nums = sorted(list(set(nums)))
    rank_map = {num: i for i, num in enumerate(sorted_nums)}

    fenwick_tree = FenwickTree(len(sorted_nums))
    result = []

    for num in reversed(nums):
        rank = rank_map[num]
        result.append(fenwick_tree.query(rank - 1))
        fenwick_tree.update(rank, 1)

    return result[::-1]
